class DSU(val size: Int) {
    private val parent: Array<Int>
    private val rank: Array<Int>

    init {
        parent = IntArray(size) { it }
        rank = IntArray(size) { 0 }
    }

    fun find(x: Int): Int {
        if (parent[x] != x) {
            parent[x] = find(parent[x])
        }
        return parent[x]
    }

    fun union(x: Int, y: Int) {
        val xRoot = find(x)
        val yRoot = find(y)
        if (xRoot == yRoot) return
        if (rank[xRoot] < rank[yRoot]) {
            parent[xRoot] = yRoot
        } else {
            parent[yRoot] = xRoot
            if (rank[xRoot] == rank[yRoot]) {
                rank[xRoot]++
            }
        }
    }

    fun countComponents(): Int {
        val roots = mutableSetOf<Int>()
        for (i in 0 until size) {
            roots.add(find(i))
        }
        return roots.size
    }
}

fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    val max_w = edges.maxOf { it[2] } ?: 0L
    var low = 0L
    var high = max_w
    var answer = max_w

    while (low <= high) {
        val mid = (low + high) / 2
        val dsu = DSU(n.toInt())
