            val v = edge[1].toInt()
            val w = edge[2]
            if (w <= mid) {
                dsu.union(u, v)
            }
        }
        val components = dsu.countComponents()
        if (components <= k) {
            answer = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }

    return answer
}
