def solve(n: int, edges: list[list[int]], k: int) -> int:
    class DSU:
        def __init__(self, size):
            self.parent = list(range(size))
            self.rank = [0] * size

        def find(self, x):
            if self.parent[x] != x:
                self.parent[x] = self.find(self.parent[x])
            return self.parent[x]

        def union(self, x, y):
            x_root = self.find(x)
            y_root = self.find(y)
            if x_root == y_root:
                return
            if self.rank[x_root] < self.rank[y_root]:
                self.parent[x_root] = y_root
            else:
                self.parent[y_root] = x_root
                if self.rank[x_root] == self.rank[y_root]:
                    self.rank[x_root] += 1

        def count_components(self):
            roots = set()
            for i in range(n):
                roots.add(self.find(i))
            return len(roots)

    max_w = max(w for u, v, w in edges)
    low, high = 0, max_w
    answer = max_w

    while low <= high:
        mid = (low + high) // 2
        dsu = DSU(n)
        for u, v, w in edges:
            if w <= mid:
                dsu.union(u, v)
        components = dsu.count_components()
        if components <= k:
            answer = mid
            high = mid - 1
        else:
            low = mid + 1

    return answer
